$content = Get-Content -Path "src\index.css" -Raw; $content = $content -replace "color:\s*var\(\-\-navy\)", "color: #000"; $content = $content -replace "color:\s*var\(\-\-maroon\)", "color: #000"; $content = $content -replace "background:\s*var\(\-\-maroon\)(?=\s*\})", "background: #000" -replace "\.section-label::before \{ content: ''; width: 24px; height: 1.5px; background: var\(\-\-maroon\); \}", ".section-label::before { content: ''; width: 24px; height: 1.5px; background: #000; }"; Set-Content -Path "src\index.css" -Value $content
